<style>
/* ---------------------------------- */
/* --- 🎨 主题与配置变量 --- */
/* ---------------------------------- */
:root {
    /* 字体 */
    --main-font: 'YshiPen-ShutiCL', KaiTi, -apple-system, Roboto, sans-serif;
    --header-font: 'Allura', sans-serif;

    /* 尺寸与间距 */
    --container-width: 550px;
