.meow_FM_thought {
    display: flex;
    justify-content: center;
    gap: 2px;
    cursor: pointer;
}

.meow_FM_thought-box {
    display: flex;
    flex-direction: column;
    align-items: center;
    position: relative;
    justify-content: flex-end;
}

.meow_FM_thought-dot {
    position: absolute;
    bottom: 26px;
    width: 12px;
    height: 12px;
    background-color: var(--SmartThemeQuoteColor);
    border-radius: 50%;
    box-shadow: 0 0 6px var(--SmartThemeUnderlineColor);
    transform-origin: bottom;
    vertical-align: bottom;
    animation: dotBounce 2s ease-in-out infinite;
}

.meow_FM_thought-char {
    font-family: "Modak";
    font-weight: 400;
    font-style: normal;
    font-display: swap;
    font-size: 2.5em;
    color: var(--SmartThemeQuoteColor);
    transform-origin: bottom;
    animation: charStretch 2s ease-in-out infinite;
    vertical-align: bottom;
}

.meow_FM_thought-box:nth-child(1) .meow_FM_thought-dot,
.meow_FM_thought-box:nth-child(1) .meow_FM_thought-char {
    animation-delay: 0.1s;
}

.meow_FM_thought-box:nth-child(2) .meow_FM_thought-char {
    animation-delay: 0.2s;
}

.meow_FM_thought-box:nth-child(3) .meow_FM_thought-char {
    animation-delay: 0.3s;
}

.meow_FM_thought-box:nth-child(4) .meow_FM_thought-char {
    animation-delay: 0.4s;
}

.meow_FM_thought-box:nth-child(5) .meow_FM_thought-char {
    animation-delay: 0.5s;
}

.meow_FM_thought-box:nth-child(6) .meow_FM_thought-char {
    animation-delay: 0.6s;
}

.meow_FM_thought-box:nth-child(7) .meow_FM_thought-dot,
.meow_FM_thought-box:nth-child(7) .meow_FM_thought-char {
    animation-delay: 0.7s;
}

@keyframes charStretch {

    0%,
    5%,
    90% {
        transform: scaleY(1);
    }

    20% {
        transform: scaleY(0.6) scaleX(1.2);
    }

    24% {

        text-shadow: none;
    }

    25% {
        transform: scaleY(1.5) scaleX(0.8);
        text-shadow: 0 0 6px var(--SmartThemeUnderlineColor);
    }

    60% {
        transform: none;
    }
}

@keyframes dotBounce {

    0%,
    25%,
    100% {
        transform: translateY(0);
    }

    35% {
        transform: translateY(-40px) scaleY(1.8)scaleX(0.6);
        animation-timing-function: ease-out;
    }

    50% {
        transform: translateY(0) scaleY(0.8)scaleX(1.2);
        animation-timing-function: ease-in;
    }

    65% {
        transform: translateY(-12px) scaleY(1.2)scaleX(0.8);
        animation-timing-function: ease-out;
    }

    85% {
        transform: translateY(0);
    }
}

@keyframes thought-fade-in {
    0% {
        opacity: 0;
        transform: translateY(-10px);
    }

    100% {
        opacity: 1;
    }
}


.meow__thinking {
    display: grid;
    width: 100%;
    place-items: center;
    position: relative;
    cursor: pointer;
}

.meow__thinking>.meow_FM_thought {
    transition: opacity 0.6s ease, transform 0.6s ease, visibility 0.6s;
}

.meow__thinking>.meow_FM_thought,
.meow__thinking>.meow_FM_thought-trigger {
    grid-area: 1 / 1;
    display: flex;
    align-items: center;
    justify-content: center;
}

details:not([open]) .meow_FM_thought {
    opacity: 1;
    transform: scale(1);
}

details:not([open]) .meow_FM_thought-trigger {
    opacity: 0;
    transform: scale(1.2);
    position: relative;
}

details[open] .meow_FM_thought {
    opacity: 0;
    transform: scale(0.6);
}

details[open] .meow_FM_thought-trigger {
    pointer-events: auto;
    opacity: 1;
    font-size: 1.2em;
    width: 100%;
    height: 100%;
    border-radius: 8px;
    color: var(--SmartThemeQuoteColor);
    box-shadow: inset 0 12px 10px -12px color-mix(in srgb, transparent, var(--SmartThemeUnderlineColor) 20%);
    transform: scale(1);
    transition: opacity 0.6s ease-in, transform 0.6s ease, visibility 0.6s, box-shadow 0.5s;
}
