<!DOCTYPE html>
<html lang="zh-CN">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>选项美化</title>

    <!-- 引入外部字体 -->
    <link rel="preconnect" href="https://fonts.googleapis.com">
    <link rel="preconnect" href="https://gstatic.com" crossorigin>
    <link href="https://fonts.googleapis.com/css2?family=Allura&family=Caveat:wght@400..700&display=swap" rel="stylesheet">
    <link rel="stylesheet" href="https://fontsapi.zeoseven.com/232/main/result.css">

<style>
/* ---------------------------------- */
/* --- 🎨 主题与配置变量 --- */
/* ---------------------------------- */
:root {
    /* 字体 */
    --main-font: 'YshiPen-ShutiCL', KaiTi, -apple-system, Roboto, sans-serif;
    --header-font: 'Allura', sans-serif;

    /* 尺寸与间距 */
    --container-width: 550px;
    --border-radius: 4px;
    --base-font-size: 1.1em;
    --header-font-size: 2em;

    /* 颜色 - 亮色模式 (默认) */
    --text-color: #cac3b7;
    --header-text-color: rgba(255, 255, 255, 0.6);
    --divider-color: rgba(255, 255, 255, 0.2);
    --glow-color: rgba(237,209,140,0.5);
    --inner-bg-color: rgba(0,0,0,0.1);
    --bg-texture-opacity: 0.1;

    /* 阴影 */
    --base-shadow-color: rgba(0, 0, 0, 0.15);

    /* 动画与过渡 */
    --transition-speed: 0.3s;
    --collapse-speed: 0.6s;
    --theme-change-speed: 0.8s;

    /* ✨ 新增：波纹动画变量 */
    --ripple-color: rgba(104, 226, 226, 0.05); /* 调整了颜色和透明度以适应背景 */
    --ripple-duration: 0.3s;

    /* 背景图 */
    --paper-bg-image: url('https://i.postimg.cc/DZbjkx5J/meow.png');
}

/* ------------------------------------- */
/* --- 📄 页面基础与字体设置 --- */
/* ------------------------------------- */
body {
    display: flex;
    justify-content: center;
    padding: 2em 20px;
    margin: 0;
    font-family: var(--main-font);
    font-size: var(--base-font-size);
    line-height: 1.2;
    color: var(--text-color);
    background-color: transparent;
    transition: color var(--theme-change-speed) ease;
}

/* --------------------------------------- */
/* --- 🃏 便签卡片布局与外观 --- */
/* --------------------------------------- */
.post-it-container {
    max-width: var(--container-width);
    width: 100%;
    position: relative;
    padding: 0.8em;
    padding-top: 3.5em; 
    padding-bottom: 1.5em;
    cursor: pointer;
    color: var(--text-color);
    background-color: transparent;
    border-radius: var(--border-radius);
    box-shadow: 0 0 6px 2px var(--base-shadow-color);
    transition: 
        transform var(--transition-speed) ease,
        color var(--theme-change-speed) ease;
}

.post-it-container::before {
    content: '';
    position: absolute;
    top: 0; left: 0;
    width: 100%; height: 100%;
    z-index: 1;
    border-radius: inherit;
    pointer-events: none;
    background-image: var(--paper-bg-image);
    background-position: left top;
    background-repeat: repeat;
    opacity: var(--bg-texture-opacity);
    box-shadow: inset 0 0 2px var(--text-color);
    transition: 
        box-shadow var(--theme-change-speed) ease,
        opacity var(--theme-change-speed) ease;
}

.corner-text {
    position: absolute;
    z-index: 3;
    font-family: var(--header-font);
    font-size: var(--header-font-size);
    color: var(--header-text-color);
    user-select: none;
    text-shadow: 0 0 2px transparent; 
    transition: 
        text-shadow var(--theme-change-speed) ease,
        color var(--theme-change-speed) ease;
}

.cat-kaomoji {
    bottom: 10px;
    left: 50%;
    transform: translateX(-50%);
    font-family: Sans-Serif;
    font-size: 15px;
    color: rgba(255, 255, 255, 0.25);
}

.corner-info {
    top: 20px;
    left: 50%;
    transform: translateX(-50%);
    white-space: nowrap;
}

.post-it-container:hover .corner-text {
    text-shadow: 
      -1px -1px 4px var(--glow-color),
      1px 1px 4px var(--glow-color);
}

/* -------------------------------------- */
/* --- 📜 可折叠内容区域 --- */
/* -------------------------------------- */
.post-it-collapsible {
    display: grid;
    grid-template-rows: 0fr;
    transition: grid-template-rows var(--collapse-speed) ease-out;
    position: relative;
    z-index: 2;
}

.post-it-collapsible.open {
    grid-template-rows: 1fr;
}

.content-wrapper {
    overflow: hidden;
    min-height: 0; 
    padding-top: 1em;
    border-top: 2px dashed var(--divider-color);
    transition: border-color var(--theme-change-speed) ease;
}

.post-it-collapsible.open .content-wrapper {
    overflow: visible;
    transition: overflow 0s linear var(--collapse-speed);
}

#options-container {
    padding-bottom: 0.5em;
}

/* --- 选项列表样式 --- */
.clickable-text {
    cursor: pointer;
    padding: 0.75em 0.75em;
    border-radius: 4px;
    margin-bottom: 0.5em;
    border: 2px ridge var(--divider-color);
    box-shadow: 0 0 1px rgba(0, 0, 0, 0.2);
    background-color: var(--inner-bg-color);
    opacity: 0;
    pointer-events: none;

    /* 为波纹动画做准备 */
    position: relative;
    overflow: hidden;
    z-index: 1;

    /* ✨ 优化点 1: 在基础规则中定义所有过渡属性 */
    transition: 
        opacity var(--theme-change-speed) ease-out 0.4s, /* 包含了延迟的淡入效果 */
        transform 0.4s ease,
        box-shadow 0.4s ease, /* 修复了笔误 0.4 -> 0.4s */
        border-color var(--theme-change-speed) ease,
        background-color var(--theme-change-speed) ease;
}

.post-it-collapsible.open .clickable-text {
    opacity: 1;
    pointer-events: auto;
    /* ✨ 优化点 1: 移除了重复的 transition 声明。 */
}

.post-it-collapsible.open .clickable-text:hover {
    box-shadow: 0 4px 8px rgba(0, 0, 0, 0.2);
    transform: translate(10%,-4px);
    z-index: 5; /* 提高层级，确保在其他选项之上 */
    /* ✨ 优化点 2: 移除了冗余的 position: relative */
}

ul, li { 
    list-style-type: none;
    padding-left: 0;
    margin: 0;
}

/* 确保 li 中的文字内容在波纹动画之上 */
.clickable-text li {
    position: relative;
    z-index: 2;
}


/* -------------------------- */
/* --- 💧 波纹动画 --- */
/* -------------------------- */
@keyframes ripple {
    from { transform: translate(-50%, -50%) scale(0); opacity: 1; }
    to   { transform: translate(-50%, -50%) scale(2.5); opacity: 0; }
}

.clickable-text::before {
    content: '';
    position: absolute;
    top: 0;
    left: 100%;
    width: 100%;
    padding-top: 100%;
    border-radius: 50%;
    background-color: var(--ripple-color);
    transform: translate(-50%, -50%) scale(0);
    opacity: 0;
    pointer-events: none;
    z-index: 1;
    animation: none;
}

.post-it-collapsible.open .clickable-text:hover::before {
    animation: ripple var(--ripple-duration) ease-out forwards;
}

</style>
</head>
<body>

<div class="post-it-container dark-mode" id="post-it-card">

    <div class="cat-kaomoji corner-text">ฅ(^・ω・^)ฅ</div>
    <div class="corner-info corner-text">Choose · Sth.</div>

    <div class="post-it-collapsible" id="collapsible-content">
        <div class="content-wrapper">
            <div id="options-container"></div>
        </div>
    </div>
</div>

<div id="raw-options-data" style="display:none;">$1</div>

<script>
document.addEventListener('DOMContentLoaded', function() {

    function initPostItCard() {
        const elements = {
            card: document.getElementById('post-it-card'),
            themeToggle: document.getElementById('theme-switcher'),
            collapsibleContent: document.getElementById('collapsible-content'),
            optionsContainer: document.getElementById('options-container'),
            rawData: document.getElementById('raw-options-data')
        };

        if (!elements.card || !elements.rawData || !elements.optionsContainer) {
            console.error("Post-it card essential elements not found.");
            return;
        }

        setupOptionList(elements.rawData, elements.optionsContainer);
        setupCollapsible(elements);
    }

    function setupOptionList(dataEl, targetContainer) {
        const rawText = dataEl.textContent.trim();
        const lines = rawText.split(/\r?\n/).filter(line => line.trim() !== '');

        lines.forEach(line => {
            const cleanText = line.trim().replace(/^[A-Z]\.\s*/i, '');
            if (!cleanText) return;

            const optionDiv = document.createElement('div');
            optionDiv.className = 'clickable-text';
            optionDiv.setAttribute('data-action', cleanText);
            optionDiv.innerHTML = `<li>${cleanText}</li>`;

            optionDiv.addEventListener('click', function() {
                const textToSend = this.getAttribute('data-action');
                try {
                    const input = window.parent.document.querySelector('#send_textarea');
                    const trigger = window.parent.triggerSlash;
                    if (input) {
                        const newValue = input.value + textToSend;
                        if (trigger) {
                            trigger(`/setinput ${newValue}`);
                        } else {
                            input.value = newValue;
                            input.dispatchEvent(new Event('input', { bubbles: true }));
                        }
                    } else if (trigger) {
                        trigger(`/setinput ${textToSend}`);
                    }
                } catch (e) {
                    console.error('Error setting input text:', e);
                }
            });
            targetContainer.appendChild(optionDiv);
        });
    }

function setupCollapsible(elements) {
    const { card, collapsibleContent, optionsContainer } = elements;

    card.addEventListener('click', (event) => {
        const interactiveElements = [
            ...optionsContainer.querySelectorAll('.clickable-text')
        ];

        const isClickOnInteractiveChild = interactiveElements.some(el => el && el.contains(event.target));

        if (!isClickOnInteractiveChild) {
            collapsibleContent.classList.toggle('open');
        }
    });
}

    initPostItCard();
});
</script>
</body>
